(function(global){
  class MiniChart {
    constructor(canvas, config){
      this.canvas = canvas && canvas.canvas ? canvas.canvas : canvas;
      this.ctx = canvas && canvas.getContext ? canvas.getContext('2d') : (canvas && canvas.canvas ? canvas : null);
      this.config = config || { type:'bar', data:{labels:[],datasets:[]} };
      this.data = this.config.data || { labels: [], datasets: [] };
      this.type = this.config.type || 'bar';
      this.render();
    }
    clear(){
      if (!this.ctx || !this.canvas) return;
      this.ctx.clearRect(0,0,this.canvas.width,this.canvas.height);
    }
    render(){
      if (!this.ctx || !this.canvas) return;
      const ratio = global.devicePixelRatio || 1;
      const rect = this.canvas.getBoundingClientRect();
      if (rect.width > 0 && rect.height > 0) {
        this.canvas.width = Math.floor(rect.width * ratio);
        this.canvas.height = Math.floor(rect.height * ratio);
        this.ctx.setTransform(ratio,0,0,ratio,0,0);
      }
      this.clear();
      const w = this.canvas.clientWidth || 300;
      const h = this.canvas.clientHeight || 150;
      const labels = this.data.labels || [];
      const ds = (this.data.datasets||[])[0] || { data:[] };
      const vals = (ds.data||[]).map((n)=>Number(n)||0);
      const max = Math.max(1,...vals);
      this.ctx.fillStyle = '#8aa0b7';
      this.ctx.font = '12px sans-serif';
      if (this.type === 'pie') {
        let total = vals.reduce((a,b)=>a+b,0) || 1;
        let a0 = -Math.PI/2;
        vals.forEach((v,i)=>{
          const a1 = a0 + (v/total)*Math.PI*2;
          this.ctx.beginPath();
          this.ctx.moveTo(w/2,h/2);
          this.ctx.arc(w/2,h/2,Math.min(w,h)*0.35,a0,a1);
          this.ctx.closePath();
          this.ctx.fillStyle = ['#4e79a7','#f28e2b','#e15759','#76b7b2','#59a14f','#edc949'][i%6];
          this.ctx.fill();
          a0 = a1;
        });
      } else {
        const horizontal = !!(this.config.options && this.config.options.indexAxis === 'y');
        vals.forEach((v,i)=>{
          this.ctx.fillStyle = (Array.isArray(ds.backgroundColor)?ds.backgroundColor[i]:ds.backgroundColor) || '#4e79a7';
          if (horizontal) {
            const bh = Math.max(8,(h-30)/Math.max(1,vals.length)-6);
            const y = 15 + i*(bh+6);
            const bw = (w-120)*(v/max);
            this.ctx.fillRect(110,y,bw,bh);
            this.ctx.fillStyle = '#8aa0b7';
            this.ctx.fillText(String(labels[i]||''),8,y+bh*0.75);
          } else {
            const bw = Math.max(8,(w-20)/Math.max(1,vals.length)-6);
            const x = 10 + i*(bw+6);
            const bh = (h-30)*(v/max);
            this.ctx.fillRect(x,h-10-bh,bw,bh);
            this.ctx.fillStyle = '#8aa0b7';
            this.ctx.fillText(String(labels[i]||''),x,h-2);
          }
        });
      }
    }
    update(){ this.render(); }
    destroy(){ this.clear(); }
    set data(next){ this._data = next || { labels:[], datasets:[] }; }
    get data(){ return this._data; }
  }
  global.Chart = MiniChart;
})(window);
